import{_ as e,c as t,a0 as i,o}from"./chunks/framework.BCLQlN4B.js";const y=JSON.parse('{"title":"IT邦 - 讓 TypeScript 成為你全端開發的 ACE !","description":"","frontmatter":{"title":"IT邦 - 讓 TypeScript 成為你全端開發的 ACE !"},"headers":[],"relativePath":"pages/docTypeScript/it/partI/typeScript-1.md","filePath":"pages/docTypeScript/it/partI/typeScript-1.md"}'),l={name:"pages/docTypeScript/it/partI/typeScript-1.md"};function r(c,a,d,p,n,s){return o(),t("div",null,a[0]||(a[0]=[i('<h1 id="_01-typescript-的發展與概論" tabindex="-1">01 TypeScript 的發展與概論 <a class="header-anchor" href="#_01-typescript-的發展與概論" aria-label="Permalink to &quot;01 TypeScript 的發展與概論&quot;">​</a></h1><h2 id="_1-1-typescript-簡介" tabindex="-1">1.1 TypeScript 簡介 <a class="header-anchor" href="#_1-1-typescript-簡介" aria-label="Permalink to &quot;1.1 TypeScript 簡介&quot;">​</a></h2><p><code>TypeScript</code> 是建立在 <code>JavaScript</code> 的基礎上，除了擁有如其名的 <code>型別系統(TypeSystem)</code> 外，也擁有額外的語法。</p><h2 id="_1-2-typescript-可以解決什麼樣的問題" tabindex="-1">1.2 TypeScript 可以解決什麼樣的問題？ <a class="header-anchor" href="#_1-2-typescript-可以解決什麼樣的問題" aria-label="Permalink to &quot;1.2 TypeScript 可以解決什麼樣的問題？&quot;">​</a></h2><h3 id="_1-2-1-使用-javascript-開發時最常遇到的問題" tabindex="-1">1.2.1 使用 JavaScript 開發時最常遇到的問題 <a class="header-anchor" href="#_1-2-1-使用-javascript-開發時最常遇到的問題" aria-label="Permalink to &quot;1.2.1 使用 JavaScript 開發時最常遇到的問題&quot;">​</a></h3><ul><li><h4 id="使用-javascript-開發時最常遇到的問題與麻煩點" tabindex="-1">使用 JavaScript 開發時最常遇到的問題與麻煩點 <a class="header-anchor" href="#使用-javascript-開發時最常遇到的問題與麻煩點" aria-label="Permalink to &quot;使用 JavaScript 開發時最常遇到的問題與麻煩點&quot;">​</a></h4><ul><li><ol><li>除錯時，除非用眼力暴力掃瞄程式碼，否則 <code>免不了執行程式的步驟</code></li></ol></li><li><ol start="2"><li>沒有工具的輔助，單純寫程式，<code>錯字機率本來就很高</code></li></ol></li><li><ol start="3"><li>由於 <code>資料格式 / 型別 / 結構錯誤</code> 等，儘管程式執行過程沒錯誤，但 <code>出現非人類預期狀況</code></li></ol></li><li><ol start="4"><li><code>忘記要處理邊緣情境</code> 相關的問題</li></ol></li></ul></li></ul><h3 id="_1-2-2-動態語言-v-s-靜態語言" tabindex="-1">1.2.2 動態語言 V.S. 靜態語言 <a class="header-anchor" href="#_1-2-2-動態語言-v-s-靜態語言" aria-label="Permalink to &quot;1.2.2 動態語言 V.S. 靜態語言&quot;">​</a></h3><ul><li><h4 id="動態與靜態語言-dynamically-v-s-statically-typed-language" tabindex="-1">動態與靜態語言 Dynamically v.s. Statically Typed Language <a class="header-anchor" href="#動態與靜態語言-dynamically-v-s-statically-typed-language" aria-label="Permalink to &quot;動態與靜態語言 Dynamically v.s. Statically Typed Language&quot;">​</a></h4><ul><li><ol><li><code>動態</code> 語言的特色為：在 <code>程式運行</code> 的狀態下，也就是在英文文章裡會看到的 <code>Run-time</code> 期間，任何變數是經由被代入值來判斷其型別；也就是說，<code>變數的型別會依據存的值本身來判斷</code>。</li></ol></li><li><ol start="2"><li><code>靜態</code> 語言的特色則是：在 <code>程式正在編譯</code> 時，也就是所謂的 <code>Compilation</code> 期間，根據程式裡 <code>宣告的型別</code> (幾乎都適用 <code>文字</code> 來表示，如 <code>Int</code>、<code>Float</code> 等) 來監控型別的狀態。</li></ol></li></ul></li><li><h4 id="漸進式型別系統-gradual-typing" tabindex="-1">漸進式型別系統 Gradual Typing <a class="header-anchor" href="#漸進式型別系統-gradual-typing" aria-label="Permalink to &quot;漸進式型別系統 Gradual Typing&quot;">​</a></h4><p>兼具動態與靜態語言的特色 - 程式碼在編譯過程中可能會遇到變數或表達式(Expression) 被顯性地型別註記，這些變數會在靜態地編譯過程中檢測並且被監控；<code>某些沒有被註記型別的變數或表達式等，會在程式裡自行推斷 (Inference) 型別之結果</code>，如果遇到型別對應錯誤時釋放警告。</p></li><li><h4 id="型別註記-型別推論" tabindex="-1">型別註記 &amp; 型別推論 <a class="header-anchor" href="#型別註記-型別推論" aria-label="Permalink to &quot;型別註記 &amp; 型別推論&quot;">​</a></h4><ul><li><h5 id="型別註記-type-annotation" tabindex="-1"><code>型別註記 (Type Annotation)</code> <a class="header-anchor" href="#型別註記-type-annotation" aria-label="Permalink to &quot;`型別註記 (Type Annotation)`&quot;">​</a></h5> 為對變數或表達式進行 <code>文字敘述上的型別宣告動作</code>。</li><li><h5 id="型別推論-type-inference" tabindex="-1"><code>型別推論 (Type Inference)</code> <a class="header-anchor" href="#型別推論-type-inference" aria-label="Permalink to &quot;`型別推論 (Type Inference)`&quot;">​</a></h5> 則是 <code>變數根據被賦予的值之型別來代表該變數之型別</code>；而表達式則是 <code>經運算結果的值之型別來代表整個表達式最後的型別結果</code>。</li></ul><p>簡而言之，撇除掉已經被註記過後的東西，決定其他沒有被註記過後的東西之型別，就是看結果值的型別是什麼就對了。</p></li></ul><h3 id="_1-2-3-強型別語言-v-s-弱型別語言" tabindex="-1">1.2.3 強型別語言 V.S. 弱型別語言 <a class="header-anchor" href="#_1-2-3-強型別語言-v-s-弱型別語言" aria-label="Permalink to &quot;1.2.3 強型別語言 V.S. 弱型別語言&quot;">​</a></h3><h2 id="_1-3-學習-typescript-的更多好處" tabindex="-1">1.3 學習 TypeScript 的更多好處 <a class="header-anchor" href="#_1-3-學習-typescript-的更多好處" aria-label="Permalink to &quot;1.3 學習 TypeScript 的更多好處&quot;">​</a></h2><h2 id="_1-4-征途路上總是也有跌跌撞撞的時候" tabindex="-1">1.4 征途路上總是也有跌跌撞撞的時候 <a class="header-anchor" href="#_1-4-征途路上總是也有跌跌撞撞的時候" aria-label="Permalink to &quot;1.4 征途路上總是也有跌跌撞撞的時候&quot;">​</a></h2><h2 id="_1-5-旅程中的第一小步" tabindex="-1">1.5 旅程中的第一小步 <a class="header-anchor" href="#_1-5-旅程中的第一小步" aria-label="Permalink to &quot;1.5 旅程中的第一小步&quot;">​</a></h2>',12)]))}const u=e(l,[["render",r]]);export{y as __pageData,u as default};
